{
  "name": "Missing NPI Check",
  "description": "Flags claims where the provider NPI is missing",
  "ruleType": "Validation",
  "conditions": {
    "field": "provider.npi",
    "operator": "isEmpty"
  },
  "actions": {
    "flag": "MissingNPI",
    "severity": "Error"
  },
  "isActive": true,
  "organizationId": "{{ _.organization_id }}"
}
